    28→/**
    29→ * Get a plugin setting with wp-config constant fallback.
    30→ *
    31→ * @param string $key Setting key.
    32→ * @param mixed $default Default value if not set.
    33→ * @return mixed Setting value.
    34→ */
    35→function agentpress_get_setting($key, $default = null) {
    36→    $settings = get_option('agentpress_settings', array());
    37→
    38→    // Check for wp-config constant override first
    39→    $constant_map = array(
    40→        'claude_api_key' => 'AGENTPRESS_CLAUDE_KEY',
    41→        'cf_worker_url' => 'AGENTPRESS_CF_WORKER_URL',
    42→        'default_model' => 'AGENTPRESS_DEFAULT_MODEL',
    43→    );
    44→
    45→    if (isset($constant_map[$key]) && defined($constant_map[$key])) {
    46→        return constant($constant_map[$key]);
    47→    }
    48→
    49→    return isset($settings[$key]) ? $settings[$key] : $default;
    50→}
