    61→    /**
    62→     * Check if the user has permission to access the API.
    63→     *
    64→     * @param WP_REST_Request $request The request object.
    65→     * @return bool|WP_Error True if permission granted, WP_Error otherwise.
    66→     */
    67→    public function check_permissions($request) {
    68→        // Check if user is authenticated (Application Password or logged in)
    69→        if (!is_user_logged_in()) {
    70→            // Try application password authentication
    71→            $user = wp_authenticate_application_password(null, wp_get_current_user()->user_login, $request->get_header('authorization'));
    72→            if (is_wp_error($user)) {
    73→                return new \WP_Error(
    74→                    'rest_forbidden',
    75→                    __('Authentication required.', 'agentpress'),
    76→                    array('status' => 401)
    77→                );
    78→            }
    79→        }
    80→
    81→        // Check if user can manage options (admin level)
    82→        if (!current_user_can('manage_options')) {
    83→            return new \WP_Error(
    84→                'rest_forbidden',
    85→                __('You do not have permission to access this endpoint.', 'agentpress'),
    86→                array('status' => 403)
    87→            );
    88→        }
    89→
    90→        return true;
    91→    }
    92→
    93→    /**
    94→     * Validate the task parameter.
    95→     *
    96→     * @param mixed $value The task value.
    97→     * @param WP_REST_Request $request The request object.
    98→     * @param string $param The parameter name.
    99→     * @return bool|WP_Error True if valid, WP_Error otherwise.
   100→     */
   101→    public function validate_task($value, $request, $param) {
   102→        if (empty($value) || !is_string($value)) {
   103→            return new \WP_Error(
   104→                'rest_invalid_param',
   105→                __('The task parameter is required and must be a non-empty string.', 'agentpress'),
   106→                array('status' => 400)
   107→            );
   108→        }
   109→
   110→        if (strlen($value) > 1000) {
   111→            return new \WP_Error(
   112→                'rest_invalid_param',
   113→                __('The task parameter must be less than 1000 characters.', 'agentpress'),
   114→                array('status' => 400)
   115→            );
   116→        }
   117→
   118→        return true;
   119→    }
   120→
   121→    /**
   122→     * Sanitize the context parameter.
   123→     *
   124→     * @param mixed $value The context value.
   125→     * @param WP_REST_Request $request The request object.
   126→     * @param string $param The parameter name.
   127→     * @return array Sanitized context.
   128→     */
   129→    public function sanitize_context($value, $request, $param) {
   130→        if (!is_array($value)) {
   131→            return array();
   132→        }
   133→
   134→        // Sanitize all string values in context
   135→        return array_map(function($item) {
   136→            return is_string($item) ? sanitize_text_field($item) : $item;
   137→        }, $value);
   138→    }
   139→
   140→    /**
   141→     * Handle the run request.
   142→     *
   143→     * @param WP_REST_Request $request The request object.
   144→     * @return WP_REST_Response The response.
   145→     */
   146→    public function handle_run_request($request) {
   147→        $start_time = microtime(true);
   148→
   149→        $task = $request->get_param('task');
   150→        $context = $request->get_param('context');
   151→
   152→        try {
   153→            // Route the task to appropriate agent
   154→            $routing = Router::route($task, $context);
   155→
   156→            // Check for routing errors
   157→            if (isset($routing['error']) && is_wp_error($routing['error'])) {
   158→                $error = $routing['error'];
   159→                $response_data = array(
   160→                    'success' => false,
   161→                    'code' => $error->get_error_code(),
   162→                    'message' => $error->get_error_message(),
   163→                    'data' => array(
   164→                        'status' => 500,
   165→                    ),
   166→                );
   167→
   168→                // Log the error
   169→                $this->log_execution($task, 'error', $routing, $start_time, $error);
   170→
   171→                return new \WP_REST_Response($response_data, 500);
   172→            }
   173→
   174→            // Check for no match
   175→            if (empty($routing['capability'])) {
   176→                $response_data = array(
   177→                    'success' => false,
   178→                    'code' => 'agentpress_no_match',
   179→                    'message' => __('No suitable agent found for this task.', 'agentpress'),
   180→                    'data' => array(
   181→                        'status' => 400,
   182→                    ),
   183→                );
   184→
   185→                // Log the no match
   186→                $this->log_execution($task, 'error', $routing, $start_time,
   187→                    new \WP_Error('agentpress_no_match', $response_data['message'])
   188→                );
   189→
   190→                return new \WP_REST_Response($response_data, 400);
   191→            }
   192→
   193→            // Execute the agent
   194→            $result = Agents::run_internal($routing['capability'], array(
   195→                'task' => $task,
   196→                'context' => $context,
   197→            ));
   198→
   199→            // Check for execution errors
   200→            if (is_wp_error($result)) {
   201→                $response_data = array(
   202→                    'success' => false,
   203→                    'code' => $result->get_error_code(),
   204→                    'message' => $result->get_error_message(),
   205→                    'data' => array(
   206→                        'status' => 500,
   207→                    ),
   208→                );
   209→
   210→                // Log the error
   211→                $this->log_execution($routing['capability'], 'error', $routing, $start_time, $result);
   212→
   213→                return new \WP_REST_Response($response_data, 500);
   214→            }
   215→
   216→            // Calculate latency
   217→            $latency_ms = round((microtime(true) - $start_time) * 1000);
   218→
   219→            // Success response
   220→            $response_data = array(
   221→                'success' => true,
   222→                'routing' => array(
   223→                    'capability' => $routing['capability'],
   224→                    'source' => $routing['source'],
   225→                    'confidence' => isset($routing['confidence']) ? $routing['confidence'] : null,
   226→                ),
   227→                'result' => $result,
   228→                'latency_ms' => $latency_ms,
   229→            );
   230→
   231→            // Log the success
   232→            $this->log_execution($routing['capability'], 'success', $routing, $start_time, $result);
   233→
   234→            return new \WP_REST_Response($response_data, 200);
   235→
   236→        } catch (Exception $e) {
   237→            $error = new \WP_Error(
   238→                'agentpress_internal_error',
   239→                __('Internal server error.', 'agentpress'),
   240→                array('status' => 500)
   241→            );
   242→
   243→            $response_data = array(
   244→                'success' => false,
   245→                'code' => $error->get_error_code(),
   246→                'message' => $error->get_error_message(),
   247→                'data' => array(
   248→                    'status' => 500,
   249→                ),
   250→            );
   251→
   252→            // Log the exception
   253→            $this->log_execution($task, 'error', array(), $start_time, $error);
   254→
   255→            return new \WP_REST_Response($response_data, 500);
   256→        }
   257→    }
   258→
   259→    /**
   260→     * Log execution details.
   261→     *
   262→     * @param string $capability The capability used.
   263→     * @param string $status Execution status (success/error).
   264→     * @param array $routing Routing information.
   265→     * @param float $start_time Start timestamp.
   266→     * @param mixed $result Result or error.
   267→     * @return void
   268→     */
   269→    private function log_execution($capability, $status, $routing, $start_time, $result) {
   270→        $latency_ms = round((microtime(true) - $start_time) * 1000);
   271→        $task = isset($_POST['task']) ? sanitize_text_field($_POST['task']) : 'Unknown task';
   272→
   273→        // Use the Logger to log the execution
   274→        Logger::log($capability, $task, $status, $latency_ms, is_wp_error($result) ? $result->get_error_message() : $result, $routing);
   275→    }
